// src/members.tsx
import React, { useEffect, useState } from "react";
import { Users, Search, Apple, UserPlus } from "lucide-react";
import { supabase } from "./lib/supabase";

export function MembersPage({ onSelectMember }: { onSelectMember: (user: any) => void }) {
  const [members, setMembers] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchMembers = async () => {
      const { data, error } = await supabase
        .from('profiles')
        .select('*')
        .order('first_name', { ascending: true });

      if (!error && data) setMembers(data);
      setLoading(false);
    };
    fetchMembers();
  }, []);

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold text-white">Atletas</h1>
          <p className="text-gray-400 mt-1">Gestiona los miembros del gimnasio y sus planes</p>
        </div>
        <button className="bg-[#39FF14] text-[#121212] px-6 py-3 rounded-lg font-bold hover:bg-[#2EE010] transition-colors flex items-center gap-2">
          <UserPlus className="w-5 h-5" />
          Añadir Atleta
        </button>
      </div>

      <div className="bg-[#1a1a1a] border border-[#2a2a2a] rounded-xl overflow-hidden">
        <table className="w-full text-left">
          <thead className="bg-[#121212] border-b border-[#2a2a2a] text-gray-400 text-xs uppercase">
            <tr>
              <th className="p-4">Nombre Completo</th>
              <th className="p-4">Rol / Estado</th>
              <th className="p-4">Fecha de Registro</th>
              <th className="p-4 text-right">Acciones</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-[#2a2a2a]">
            {loading ? (
              <tr>
                <td colSpan={4} className="p-10 text-center text-[#39FF14] animate-pulse">
                  Cargando base de datos de atletas...
                </td>
              </tr>
            ) : members.length === 0 ? (
              <tr>
                <td colSpan={4} className="p-10 text-center text-gray-500">
                  No se encontraron atletas registrados.
                </td>
              </tr>
            ) : (
              members.map((member) => (
                <tr key={member.id} className="hover:bg-white/5 transition-colors group">
                  <td className="p-4 flex items-center gap-3">
                    <div className="w-10 h-10 bg-[#39FF14]/10 rounded-full flex items-center justify-center border border-[#39FF14]/20 text-[#39FF14] font-bold">
                      {member.first_name?.[0] || 'U'}
                    </div>
                    <div>
                      <p className="font-bold text-white">{member.first_name} {member.last_name}</p>
                      <p className="text-xs text-gray-500">{member.full_name || 'Sin nombre de usuario'}</p>
                    </div>
                  </td>
                  <td className="p-4">
                    <span className="px-3 py-1 bg-blue-500/10 text-blue-400 border border-blue-500/20 rounded-full text-[10px] font-bold uppercase">
                      {member.role || 'Cliente'}
                    </span>
                  </td>
                  <td className="p-4 text-sm text-gray-400">
                    {member.created_at ? new Date(member.created_at).toLocaleDateString('es-ES') : '---'}
                  </td>
                  <td className="p-4 text-right">
                    <button 
                      onClick={() => onSelectMember(member)}
                      className="bg-[#121212] border border-[#2a2a2a] text-[#39FF14] px-4 py-2 rounded-lg text-sm font-bold hover:bg-[#39FF14] hover:text-black transition-all flex items-center gap-2 ml-auto"
                    >
                      <Apple size={14} /> Plan Nutricional
                    </button>
                  </td>
                </tr>
              ))
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
}
